#!/usr/bin/env node
/**
 * P0-06: pnpm is the canonical lockfile; bun.lock is optional (generated by `bun install`).
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const pkg = JSON.parse(fs.readFileSync(path.join(root, "package.json"), "utf8"));

let ok = true;

if (!fs.existsSync(path.join(root, "pnpm-lock.yaml"))) {
  console.error("missing pnpm-lock.yaml");
  ok = false;
}

if (!pkg.packageManager?.startsWith("pnpm@")) {
  console.error('package.json "packageManager" must pin pnpm');
  ok = false;
}

const bunLock = ["bun.lock", "bun.lockb"].find((name) => fs.existsSync(path.join(root, name)));
if (bunLock) {
  console.log(`optional ${bunLock} present (bun install)`);
} else {
  console.log("bun lockfile absent (ok — run bun install locally if needed)");
}

if (!ok) process.exit(1);

console.log("lockfiles ok: pnpm-lock.yaml + packageManager");
